from fastapi import APIRouter, Query
from datetime import date
from typing import Optional
from services.projection_service import calculate_two_week_projection
from services.forecast_dto import ForecastResponseDTO

router = APIRouter()


@router.get("/forecast")
def get_14_day_forecast(as_of_date: Optional[str] = Query(None)):
    """
    Return a deterministic 14-day projection of account balances.

    Query Parameters:
        as_of_date (optional): Reference date in ISO format (YYYY-MM-DD).
                              Defaults to today if not provided.

    Returns:
        ForecastResponseDTO: JSON containing daily balance timeline and Safe-to-Spend.

    Deterministic, read-only, multi-account aware.
    """
    # Parse optional as_of_date parameter
    if as_of_date:
        try:
            as_of = date.fromisoformat(as_of_date)
        except ValueError:
            return {"error": "Invalid date format. Use YYYY-MM-DD."}
    else:
        as_of = None

    try:
        # Compute projection using deterministic engine
        projection = calculate_two_week_projection(as_of_date=as_of)

        # Convert to JSON-serializable DTO
        dto = ForecastResponseDTO.from_projection(projection)

        # Return as dict so FastAPI can serialize to JSON
        return {
            "start_date": dto.start_date,
            "end_date": dto.end_date,
            "starting_balance": dto.starting_balance,
            "safe_to_spend": dto.safe_to_spend,
            "timeline": [
                {"date": day.date, "projected_balance": day.projected_balance}
                for day in dto.timeline
            ]
        }
    except Exception as e:
        return {"error": str(e)}

from fastapi import APIRouter, UploadFile, File, HTTPException
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import Optional

from services.csv_ingest_service import ingest_csv
from services.transaction_service import (
    get_all_transactions,
    update_transaction_category,
    add_transaction,
    reclassify_all_transactions,
    get_filtered_transactions,
)
from repositories.accounts_repository import get_or_create_account

router = APIRouter()


# -------------------------
# SIMPLE UPLOAD PAGE
# -------------------------

@router.get("/upload", response_class=HTMLResponse)
def upload_page():
    return """
    <html>
        <body style="font-family: Arial; padding: 40px;">
            <h2>Upload Bank CSV</h2>
            <form action="/upload" method="post" enctype="multipart/form-data">
                <input type="file" name="file" accept=".csv" required>
                <button type="submit">Upload</button>
            </form>
            <br>
            <a href="/dashboard">Back to Dashboard</a>
        </body>
    </html>
    """


# -------------------------
# CSV INGESTION
# -------------------------

@router.post("/upload")
def upload_csv(file: UploadFile = File(...)):
    contents_bytes = file.file.read()

    try:
        contents = contents_bytes.decode("utf-8-sig")
    except UnicodeDecodeError:
        return {
            "success": False,
            "error": "File must be UTF-8 encoded CSV"
        }

    return ingest_csv(contents)


# -------------------------
# READ TRANSACTIONS
# -------------------------

@router.get("/transactions/from-db")
def get_transactions_from_db():
    return {"transactions": get_all_transactions()}


@router.get("/transactions")
def get_transactions(
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    category: Optional[str] = None,
    account_id: Optional[int] = None,
):
    if start_date is None and end_date is None and category is None and account_id is None:
        return {"transactions": get_all_transactions()}

    return {
        "transactions": get_filtered_transactions(
            start_date=start_date,
            end_date=end_date,
            category=category,
            account_id=account_id,
        )
    }


# -------------------------
# UPDATE CATEGORY
# -------------------------

@router.put("/transactions/{transaction_id}/category")
def update_category(transaction_id: int, category: str):
    update_transaction_category(transaction_id, category)
    return {"success": True}


# -------------------------
# MANUAL TRANSACTION ADD
# -------------------------

class ManualTransaction(BaseModel):
    account_name: str
    date: str  # ISO format YYYY-MM-DD
    description: str
    amount: float
    balance: Optional[float] = None
    category: Optional[str] = None
    source: Optional[str] = "Manual"


@router.post("/transactions/manual")
def add_manual_transaction(tx: ManualTransaction):
    # Ensure account exists (multi-account support)
    account = get_or_create_account(tx.account_name)
    account_id = account["id"]

    try:
        add_transaction(
            account_id=account_id,
            date=tx.date,
            description=tx.description,
            amount=tx.amount,
            balance=tx.balance,
            category=tx.category,
            source=tx.source,
        )
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Insert failed: {e}")

    return {"success": True, "message": "Transaction added"}


